import{_ as a,o as t,c as s,a2 as i}from"./chunks/framework.DeNJmwJc.js";const p=JSON.parse('{"title":"Chapter 63 — Common Mistakes","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/63-common-mistakes.md","filePath":"chapters/63-common-mistakes.md"}'),o={name:"chapters/63-common-mistakes.md"};function n(r,e,l,m,d,h){return t(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="chapter-63-—-common-mistakes" tabindex="-1">Chapter 63 — Common Mistakes <a class="header-anchor" href="#chapter-63-—-common-mistakes" aria-label="Permalink to &quot;Chapter 63 — Common Mistakes&quot;">​</a></h1><blockquote><p><em>&quot;Learn from others&#39; mistakes. These are the most common Vim pitfalls.&quot;</em></p></blockquote><hr><p><strong>Difficulty:</strong> ⭐⭐ Beginner-Intermediate <strong>Estimated Reading Time:</strong> 15 minutes</p><hr><h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>Every Vim user makes these mistakes at some point.</p><p>Knowing them will save you time and frustration.</p><hr><h1 id="mistake-1-staying-in-insert-mode" tabindex="-1">Mistake 1: Staying in Insert Mode <a class="header-anchor" href="#mistake-1-staying-in-insert-mode" aria-label="Permalink to &quot;Mistake 1: Staying in Insert Mode&quot;">​</a></h1><p>Many beginners stay in insert mode and use arrow keys.</p><p>This defeats the purpose of Vim.</p><p><strong>Fix:</strong> Return to normal mode as soon as you finish typing.</p><hr><h1 id="mistake-2-using-the-mouse" tabindex="-1">Mistake 2: Using the Mouse <a class="header-anchor" href="#mistake-2-using-the-mouse" aria-label="Permalink to &quot;Mistake 2: Using the Mouse&quot;">​</a></h1><p>The mouse is slow compared to keyboard commands.</p><p><strong>Fix:</strong> Force yourself to use <code>h</code>/<code>j</code>/<code>k</code>/<code>l</code> and <code>/search</code>.</p><hr><h1 id="mistake-3-not-using-the-dot-command" tabindex="-1">Mistake 3: Not Using the Dot Command <a class="header-anchor" href="#mistake-3-not-using-the-dot-command" aria-label="Permalink to &quot;Mistake 3: Not Using the Dot Command&quot;">​</a></h1><p>Manually repeating an edit instead of using <code>.</code>.</p><p><strong>Fix:</strong> Think &quot;can I use the dot command here?&quot;</p><hr><h1 id="mistake-4-overusing-visual-mode" tabindex="-1">Mistake 4: Overusing Visual Mode <a class="header-anchor" href="#mistake-4-overusing-visual-mode" aria-label="Permalink to &quot;Mistake 4: Overusing Visual Mode&quot;">​</a></h1><p>Visual mode is useful, but operator+motion is often faster.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Instead of: v$d</span></span>
<span class="line"><span>Use:        D</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Instead of: viwd</span></span>
<span class="line"><span>Use:        diw</span></span></code></pre></div><hr><h1 id="mistake-5-ignoring-registers" tabindex="-1">Mistake 5: Ignoring Registers <a class="header-anchor" href="#mistake-5-ignoring-registers" aria-label="Permalink to &quot;Mistake 5: Ignoring Registers&quot;">​</a></h1><p>Using only the unnamed register.</p><p><strong>Fix:</strong> Use named registers (<code>&quot;a</code>-<code>&quot;z</code>) for multiple clipboards.</p><hr><h1 id="mistake-6-not-using-relative-numbers" tabindex="-1">Mistake 6: Not Using Relative Numbers <a class="header-anchor" href="#mistake-6-not-using-relative-numbers" aria-label="Permalink to &quot;Mistake 6: Not Using Relative Numbers&quot;">​</a></h1><p>Without relative numbers, you can&#39;t use <code>5j</code> or <code>d5j</code> easily.</p><p><strong>Fix:</strong> Enable <code>set relativenumber</code>.</p><hr><h1 id="mistake-7-installing-too-many-plugins" tabindex="-1">Mistake 7: Installing Too Many Plugins <a class="header-anchor" href="#mistake-7-installing-too-many-plugins" aria-label="Permalink to &quot;Mistake 7: Installing Too Many Plugins&quot;">​</a></h1><p>Plugin overload makes Vim slow and complex.</p><p><strong>Fix:</strong> Start with a minimal setup. Add plugins only when needed.</p><hr><h1 id="chapter-summary" tabindex="-1">Chapter Summary <a class="header-anchor" href="#chapter-summary" aria-label="Permalink to &quot;Chapter Summary&quot;">​</a></h1><ul><li>Stay in normal mode as much as possible.</li><li>Avoid the mouse and learn keyboard commands.</li><li>Use the dot command for repetition.</li><li>Prefer operator+motion over visual mode.</li><li>Use named registers for multiple clipboards.</li><li>Enable relative numbers.</li><li>Keep your plugin setup minimal.</li></ul><hr><h2 id="exercises" tabindex="-1">Exercises <a class="header-anchor" href="#exercises" aria-label="Permalink to &quot;Exercises&quot;">​</a></h2><ol><li>Identify which of these mistakes you make most often.</li><li>Spend a day focusing on fixing one mistake.</li><li>Repeat until all bad habits are corrected.</li></ol><hr><h2 id="next-chapter" tabindex="-1">Next Chapter <a class="header-anchor" href="#next-chapter" aria-label="Permalink to &quot;Next Chapter&quot;">​</a></h2><p><a href="./64-practice-exercises.html"><strong>Chapter 64 — Practice Exercises</strong></a></p><p>Practice exercises to build your Vim skills.</p>`,47)])])}const u=a(o,[["render",n]]);export{p as __pageData,u as default};
